package com.school.sis.grade.entity;
import com.school.sis.auth.entity.User; import com.school.sis.common.audit.AuditableEntity; import com.school.sis.schedule.entity.ClassSchedule; import jakarta.persistence.*; import java.math.BigDecimal; import java.time.Instant; import java.util.*;
@Entity @Table(name="class_gradebooks") public class ClassGradebook extends AuditableEntity {
 @Id private UUID id; @OneToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="schedule_id",unique=true) private ClassSchedule schedule; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="template_id") private GradingTemplate template; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="scale_id") private GradingScale scale; @Column(name="midterm_weight",nullable=false) private BigDecimal midtermWeight; @Column(name="final_weight",nullable=false) private BigDecimal finalWeight; @Enumerated(EnumType.STRING) @Column(nullable=false) private GradeStatus status=GradeStatus.DRAFT; @Column(name="latest_correction_reason") private String latestCorrectionReason; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="initialized_by") private User initializedBy; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="submitted_by") private User submittedBy; @Column(name="submitted_at") private Instant submittedAt; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="approved_by") private User approvedBy; @Column(name="approved_at") private Instant approvedAt; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="locked_by") private User lockedBy; @Column(name="locked_at") private Instant lockedAt; @OneToMany(mappedBy="gradebook",cascade=CascadeType.ALL,orphanRemoval=true) private List<ClassGradebookCategory> categories=new ArrayList<>(); @OneToMany(mappedBy="gradebook",cascade=CascadeType.ALL,orphanRemoval=true) private List<GradeAssessmentItem> items=new ArrayList<>();
 @PrePersist void pre(){if(id==null)id=UUID.randomUUID();} public UUID getId(){return id;} public ClassSchedule getSchedule(){return schedule;} public void setSchedule(ClassSchedule v){schedule=v;} public GradingTemplate getTemplate(){return template;} public void setTemplate(GradingTemplate v){template=v;} public GradingScale getScale(){return scale;} public void setScale(GradingScale v){scale=v;} public BigDecimal getMidtermWeight(){return midtermWeight;} public void setMidtermWeight(BigDecimal v){midtermWeight=v;} public BigDecimal getFinalWeight(){return finalWeight;} public void setFinalWeight(BigDecimal v){finalWeight=v;} public GradeStatus getStatus(){return status;} public void setStatus(GradeStatus v){status=v;} public String getLatestCorrectionReason(){return latestCorrectionReason;} public void setLatestCorrectionReason(String v){latestCorrectionReason=v;} public User getInitializedBy(){return initializedBy;} public void setInitializedBy(User v){initializedBy=v;} public User getSubmittedBy(){return submittedBy;} public void setSubmittedBy(User v){submittedBy=v;} public Instant getSubmittedAt(){return submittedAt;} public void setSubmittedAt(Instant v){submittedAt=v;} public User getApprovedBy(){return approvedBy;} public void setApprovedBy(User v){approvedBy=v;} public Instant getApprovedAt(){return approvedAt;} public void setApprovedAt(Instant v){approvedAt=v;} public User getLockedBy(){return lockedBy;} public void setLockedBy(User v){lockedBy=v;} public Instant getLockedAt(){return lockedAt;} public void setLockedAt(Instant v){lockedAt=v;} public List<ClassGradebookCategory> getCategories(){return categories;} public void addCategory(ClassGradebookCategory c){c.setGradebook(this);categories.add(c);} public List<GradeAssessmentItem> getItems(){return items;} public void addItem(GradeAssessmentItem i){i.setGradebook(this);items.add(i);}
}
